import (
  appcustominvoicing "github.com/openmeterio/openmeter/openmeter/app/custominvoicing"
  "github.com/openmeterio/openmeter/openmeter/billing"
  billingtest "github.com/openmeterio/openmeter/test/billing"
)

type MyTestSuite struct { billingtest.BaseSuite }

func (s *MyTestSuite) TestFlow() {
  ctx := context.Background()
  namespace := "ns-my-unique-test"
  s.setupDefaultBillingProfile(ctx, namespace, appcustominvoicing.Configuration{EnableDraftSyncHook: true})
  invoices, _ := s.BillingService.InvoicePendingLines(ctx, billing.InvoicePendingLinesInput{...})
  s.Equal(billing.StandardInvoiceStatusDraftSyncing, invoices[0].Status)
  synced, _ := s.CustomInvoicingService.SyncDraftInvoice(ctx, appcustominvoicing.SyncDraftInvoiceInput{InvoiceID: invoices[0].GetInvoiceID(), ...})
  s.Equal(billing.StandardInvoiceStatusIssuingSyncing, synced.Status)
}

import (
  "github.com/openmeterio/openmeter/openmeter/app"
  stripeclient "github.com/openmeterio/openmeter/openmeter/app/stripe/client"
)

func (s *AppHandlerTestSuite) TestGet(ctx context.Context, t *testing.T) {
  s.setupNamespace(t)
  s.Env.StripeClient().On("GetAccount").Return(stripeclient.StripeAccount{StripeAccountID: getStripeAccountId()}, nil)
  s.Env.StripeClient().On("SetupWebhook", mock.Anything).Return(stripeclient.StripeWebhookEndpoint{EndpointID: "we_123", Secret: "whsec_123"}, nil)
  defer s.Env.StripeClient().Restore()
  created, err := s.Env.App().InstallMarketplaceListingWithAPIKey(ctx, app.InstallAppWithAPIKeyInput{
    InstallAppInput: app.InstallAppInput{MarketplaceListingID: app.MarketplaceListingID{Type: app.AppTypeStripe}, Namespace: s.namespace},
    APIKey: TestStripeAPIKey,
  })
  require.NoError(t, err)
  got, err := s.Env.App().GetApp(ctx, created.GetID())
  require.NoError(t, err)
  require.Equal(t, created.GetID(), got.GetID())
}
